// 假定获取输入的query对象
let inputQuery = $input.all()[0].json.query;

// 从输入对象中读取开始和结束日期
let activeDate_Start = inputQuery.ActiveDate_Start;
let activeDate_End = inputQuery.ActiveDate_End;

// 将字符串日期转换为Date对象
let startDate = new Date(activeDate_Start);
let endDate = new Date(activeDate_End);

// 将每月的时间段存储到categories和timeIntervals中
let categories = [];
let timeIntervals = [];

while (startDate < endDate) {
  // 当前处理的月份的年月
  let year = startDate.getFullYear();
  let month = (startDate.getMonth() + 1).toString().padStart(2, '0'); // 格式化月为两位数

  // 计算本月的结束日期
  let endOfMonth = new Date(year, startDate.getMonth() + 1, 0);

  // 如果本月结束日期超过了endDate，则使用endDate
  if (endOfMonth > endDate) {
    endOfMonth = endDate;
  }

  // 添加到categories的显示月份,包含年份
  let category = `${year}年${month}月`;
  categories.push(category);

  // 创建时间段,格式[开始时间, 结束时间]
  timeIntervals.push([
    startDate.toISOString().split('T')[0], // 当前月份的开始日期
    endOfMonth.toISOString().split('T')[0] // 当前月份的结束日期
  ]);

  // 更新下一个区间的开始日期
  startDate = new Date(year, startDate.getMonth() + 1, 1);
}

// 获取机型列表
let firmware_types = JSON.parse(inputQuery.firmware_type);

// 存储最终的查询参数列表
let queryList = [];

// 对每个机型生成一个查询参数对象
for (let firmware_type of firmware_types) {
  let { firmware_type: _, ...query } = inputQuery; // 排除原始查询参数中的 "firmType" 属性
  query = {
    ...query, // 其他原始查询参数
    "categories": categories,
    "timeIntervals": timeIntervals,
    "firmware_type": firmware_type // 使用当前循环的机型值
  };
  queryList.push(query);
}


// 返回查询参数列表
return queryList;

// 获取唯一的categories值
const categoriesSet = new Set($input.all().map(item => item.json.categories[0]));
const categoriesData = Array.from(categoriesSet).sort();

// 构建包含国家和对应数据的对象
const firmware_typeMap = new Map();
$input.all().forEach(item => {
  const firmware_type = item.json.firmware_type;
  const category = item.json.categories[0];
  const defectiveCount = parseInt(item.json.defectivecount);

  if (!firmware_typeMap.has(firmware_type)) {
    firmware_typeMap.set(firmware_type, {});
  }

  if (!firmware_typeMap.get(firmware_type)[category]) {
    firmware_typeMap.get(firmware_type)[category] = { defectivecount: 0, activecount: 0 };
  }

  firmware_typeMap.get(firmware_type)[category].defectivecount = defectiveCount;
});

// 将 activecount 数据加入到countryMap中
$('整理查询结果').all().forEach(item => {
  const firmware_type = item.json.firmware_type;
  const category = item.json.categories[0];
  const activeCount = parseInt(item.json.activecount);

  if (!firmware_typeMap.has(firmware_type)) {
    firmware_typeMap.set(firmware_type, {});
  }

  if (!firmware_typeMap.get(firmware_type)[category]) {
    firmware_typeMap.get(firmware_type)[category] = { defectivecount: 0, activecount: 0 };
  }

  firmware_typeMap.get(firmware_type)[category].activecount = activeCount;
});

// 生成最终的数据结构
const result = [];
firmware_typeMap.forEach((categories, firmware_type) => {
  const defectiveCounts = categoriesData.map(category => categories[category]?.defectivecount || 0);
  const activeCounts = categoriesData.map(category => categories[category]?.activecount || 0);

  result.push({ 
    name: firmware_type, 
    defectivecounts: defectiveCounts, 
    activecounts: activeCounts 
  });
});

return {
  result: result,
  categoriesData: categoriesData // 保留categoriesData作为可能有用的引用
};

