const firmwareTypes = $('划分时间区间1').all().map(item => item.json.firmware_type);
const counts = $('划分时间区间1').all().map(item => item.json.count);
const activeDateStarts = $('划分时间区间1').all().map(item => item.json.ActiveDate_Start);
const activeDateEnds = $('划分时间区间1').all().map(item => item.json.ActiveDate_End);

const List = firmwareTypes.flatMap((firmware_type, firmware_typeIndex) => {
  const timeIntervals = $('划分时间区间1').all()[firmware_typeIndex].json.timeIntervals;
  const categories = $('划分时间区间1').all()[firmware_typeIndex].json.categories;

  return timeIntervals.map((interval, intervalIndex) => {
    return {
      firmware_type: firmware_type,
      count: counts[firmware_typeIndex],
      ActiveDate_Start: activeDateStarts[firmware_typeIndex],
      ActiveDate_End: activeDateEnds[firmware_typeIndex],
      categories: [categories[intervalIndex]],
      timeIntervals: [interval]
    };
  });
});

return List;
